// LoadMembers loads the workspace's Members into the .R struct
func (o *Workspace) LoadMembers(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Members = nil

	related, err := o.Members(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Workspace = o
	}

	o.R.Members = related
	return nil
}

// LoadMembers loads the workspace's Members into the .R struct
func (os WorkspaceSlice) LoadMembers(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	members, err := os.Members(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Members = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range members {

			if !(o.ID == rel.WorkspaceID) {
				continue
			}

			rel.R.Workspace = o

			o.R.Members = append(o.R.Members, rel)
		}
	}

	return nil
}

