type workspaceJoins[Q dialect.Joinable] struct {
	typ          string
	Members      modAs[Q, memberColumns]
	Projects     modAs[Q, projectColumns]
	TaskComments modAs[Q, taskCommentColumns]
	Tasks        modAs[Q, taskColumns]
}

func (j workspaceJoins[Q]) aliasedAs(alias string) workspaceJoins[Q] {
	return buildWorkspaceJoins[Q](buildWorkspaceColumns(alias), j.typ)
}

func buildWorkspaceJoins[Q dialect.Joinable](cols workspaceColumns, typ string) workspaceJoins[Q] {
	return workspaceJoins[Q]{
		typ: typ,
		Members: modAs[Q, memberColumns]{
			c: Members.Columns,
			f: func(to memberColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Members.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Projects: modAs[Q, projectColumns]{
			c: Projects.Columns,
			f: func(to projectColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Projects.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		TaskComments: modAs[Q, taskCommentColumns]{
			c: TaskComments.Columns,
			f: func(to taskCommentColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, TaskComments.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Tasks: modAs[Q, taskColumns]{
			c: Tasks.Columns,
			f: func(to taskColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Tasks.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
